export * from './marker.component';
export * from './marker-icon.component';
export * from './marker-content.component';
export * from './marker.variants';
export * from './marker.imports';

import {
  ChangeDetectionStrategy,
  Component,
  computed,
  input,
  ViewEncapsulation,
} from '@angular/core';

import { cn, type ClassValue } from '{{alias}}/utils';
import { markerContentVariants } from './marker.variants';

@Component({
  selector: 'hb-marker-content, [hb-marker-content]',
  template: `<ng-content />`,
  changeDetection: ChangeDetectionStrategy.OnPush,
  encapsulation: ViewEncapsulation.None,
  host: {
    '[class]': 'classes()',
    '[attr.data-slot]': "'marker-content'",
  },
  exportAs: 'hbMarkerContent',
})
export class HbMarkerContentComponent {
  readonly class = input<ClassValue>('');
  protected readonly classes = computed(() => cn(markerContentVariants(), this.class()));
}

import {
  ChangeDetectionStrategy,
  Component,
  computed,
  input,
  ViewEncapsulation,
} from '@angular/core';

import { cn, type ClassValue } from '{{alias}}/utils';
import { markerIconVariants } from './marker.variants';

@Component({
  selector: 'hb-marker-icon, [hb-marker-icon]',
  template: `<ng-content />`,
  changeDetection: ChangeDetectionStrategy.OnPush,
  encapsulation: ViewEncapsulation.None,
  host: {
    '[class]': 'classes()',
    '[attr.data-slot]': "'marker-icon'",
    'aria-hidden': 'true',
  },
  exportAs: 'hbMarkerIcon',
})
export class HbMarkerIconComponent {
  readonly class = input<ClassValue>('');
  protected readonly classes = computed(() => cn(markerIconVariants(), this.class()));
}

import {
  booleanAttribute,
  ChangeDetectionStrategy,
  Component,
  computed,
  input,
  ViewEncapsulation,
} from '@angular/core';

import { HbSpinnerComponent } from '{{alias}}/spinner';
import { cn, type ClassValue } from '{{alias}}/utils';
import {
  markerContentVariants,
  markerLineVariants,
  markerVariants,
  type HbMarkerVariant,
} from './marker.variants';

@Component({
  selector: 'hb-marker, a[hb-marker], button[hb-marker], [hb-marker]',
  imports: [HbSpinnerComponent],
  template: `
    @if (isSeparator()) {
      <span [class]="lineClasses" aria-hidden="true"></span>
    }

    @if (hbLoading()) {
      <hb-spinner hbSize="xs" [hbLabel]="hbLoadingLabel()" class="shrink-0" />
    } @else {
      <ng-content select="hb-marker-icon, [hb-marker-icon]" />
    }

    <span [class]="contentClasses()">
      <ng-content select="hb-marker-content, [hb-marker-content]" />
      <ng-content />
    </span>

    @if (isSeparator()) {
      <span [class]="lineClasses" aria-hidden="true"></span>
    }
  `,
  styles: `
    @keyframes hb-marker-shimmer {
      from {
        background-position: 200% 0;
      }
      to {
        background-position: -200% 0;
      }
    }
    .hb-marker-shimmer {
      background-image: linear-gradient(
        90deg,
        currentColor 0%,
        currentColor 35%,
        color-mix(in oklab, currentColor 25%, transparent) 50%,
        currentColor 65%,
        currentColor 100%
      );
      background-size: 200% 100%;
      -webkit-background-clip: text;
      background-clip: text;
      -webkit-text-fill-color: transparent;
      animation: hb-marker-shimmer 1.6s linear infinite;
    }
  `,
  changeDetection: ChangeDetectionStrategy.OnPush,
  encapsulation: ViewEncapsulation.None,
  host: {
    '[class]': 'classes()',
    '[attr.data-slot]': "'marker'",
    '[attr.data-variant]': 'hbVariant()',
    '[attr.role]': 'roleAttr()',
    '[attr.aria-live]': "hbLoading() ? 'polite' : null",
    '[attr.aria-busy]': "hbLoading() ? 'true' : null",
  },
  exportAs: 'hbMarker',
})
export class HbMarkerComponent {
  readonly hbVariant = input<HbMarkerVariant>('default');
  readonly hbLoading = input(false, { transform: booleanAttribute });
  readonly hbLoadingLabel = input('Loading');
  readonly hbShimmer = input(false, { transform: booleanAttribute });
  readonly hbRole = input<string | null>(null);
  readonly class = input<ClassValue>('');

  protected readonly isSeparator = computed(() => this.hbVariant() === 'separator');
  protected readonly lineClasses = markerLineVariants();
  protected readonly classes = computed(() =>
    cn(markerVariants({ variant: this.hbVariant() }), this.class()),
  );
  protected readonly contentClasses = computed(() =>
    cn(markerContentVariants(), this.hbShimmer() && 'hb-marker-shimmer'),
  );
  protected readonly roleAttr = computed(() => (this.hbLoading() ? 'status' : this.hbRole()));
}

import { HbMarkerComponent } from './marker.component';
import { HbMarkerContentComponent } from './marker-content.component';
import { HbMarkerIconComponent } from './marker-icon.component';

export const HbMarkerImports = [
  HbMarkerComponent,
  HbMarkerIconComponent,
  HbMarkerContentComponent,
] as const;

import { cva, type VariantProps } from 'class-variance-authority';

export const markerVariants = cva(
  'inline-flex items-center gap-2 text-sm text-muted-foreground outline-none ' +
    '[&:where(a,button)]:cursor-pointer [&:where(a,button)]:rounded-sm [&:where(a,button)]:transition-colors ' +
    '[&:where(a,button)]:hover:text-foreground ' +
    '[&:where(a,button)]:focus-visible:ring-2 [&:where(a,button)]:focus-visible:ring-ring [&:where(a,button)]:focus-visible:ring-offset-2 [&:where(a,button)]:focus-visible:ring-offset-background',
  {
    variants: {
      variant: {
        default: '',
        border: 'w-full border-b border-border pb-2',
        separator: 'flex w-full items-center gap-3 text-xs',
      },
    },
    defaultVariants: { variant: 'default' },
  },
);

export const markerIconVariants = cva(
  'inline-flex shrink-0 items-center justify-center text-current [&_svg]:pointer-events-none [&_svg]:size-4',
);

export const markerContentVariants = cva('min-w-0');

export const markerLineVariants = cva('h-px flex-1 bg-border');

export type HbMarkerVariant = NonNullable<VariantProps<typeof markerVariants>['variant']>;

